insert into question_modules (id,title,eyebrow,description,target_question_count) values ('fares','Learn Fares lesson by lesson.','Fares module','Study fare topics in focused lessons, take a mini quiz, review wrong answers, and finish with a mixed Fares test using every loaded original question.',44) on conflict (id) do update set title=excluded.title, eyebrow=excluded.eyebrow, description=excluded.description, target_question_count=excluded.target_question_count;
insert into question_lessons (id,module_id,title,intro,memory_trick,is_final_test) values ('fare-basics','fares','Fare Basics','Start with the core ideas: fare receipt, basic charges, and passenger expectations.','Receipt and basic fare questions are about clarity and honesty.',false) on conflict (id) do update set title=excluded.title, intro=excluded.intro, memory_trick=excluded.memory_trick, is_final_test=excluded.is_final_test;
insert into question_lessons (id,module_id,title,intro,memory_trick,is_final_test) values ('standard-premium-special-rates','fares','Standard, Premium and Special Rates','Learn when standard, premium and special rates apply.','Standard is normal weekday daytime. Premium is nights/Sundays. Special is Christmas/New Year and special periods.',false) on conflict (id) do update set title=excluded.title, intro=excluded.intro, memory_trick=excluded.memory_trick, is_final_test=excluded.is_final_test;
insert into question_lessons (id,module_id,title,intro,memory_trick,is_final_test) values ('tariff-a-tariff-b','fares','Tariff A and Tariff B','Learn where Tariff A ends and Tariff B begins.','A comes first. B begins after the threshold.',false) on conflict (id) do update set title=excluded.title, intro=excluded.intro, memory_trick=excluded.memory_trick, is_final_test=excluded.is_final_test;
insert into question_lessons (id,module_id,title,intro,memory_trick,is_final_test) values ('time-vs-distance-charging','fares','Time vs Distance Charging','Understand when a fare is charged by journey time instead of distance.','Slow traffic means time. Below 21.2 km/h means time charging.',false) on conflict (id) do update set title=excluded.title, intro=excluded.intro, memory_trick=excluded.memory_trick, is_final_test=excluded.is_final_test;
insert into question_lessons (id,module_id,title,intro,memory_trick,is_final_test) values ('extra-charges','fares','Extra Charges','Know valid extra charges: booking, tolls, children/passengers, soiling and what cannot be charged.','Extras need a rule. Luggage is not an extra.',false) on conflict (id) do update set title=excluded.title, intro=excluded.intro, memory_trick=excluded.memory_trick, is_final_test=excluded.is_final_test;
insert into question_lessons (id,module_id,title,intro,memory_trick,is_final_test) values ('taximeter-rules','fares','Taximeter Rules','Learn taximeter start, visibility, calibration and fitting rules.','Meter must be visible, fitted, calibrated and used correctly.',false) on conflict (id) do update set title=excluded.title, intro=excluded.intro, memory_trick=excluded.memory_trick, is_final_test=excluded.is_final_test;
